import { readFile, writeFile } from 'node:fs/promises';

const root = new URL('../../', import.meta.url);
const manifestUrl = new URL('config/d1-shards.json', root);
const targets = [
  'siliconbeest/wrangler.jsonc',
  'siliconbeest/wrangler.typegen.jsonc',
  'siliconbeest-queue-consumer/wrangler.jsonc',
  'siliconbeest-email-sender/wrangler.jsonc',
];
const RESOURCE_BINDING_ESTIMATED_BYTES = 150;
const SCRIPT_METADATA_LIMIT_BYTES = 1_000_000;
const DOCUMENTED_D1_BINDING_LIMIT = 5_000;

function databaseId(shard) {
  if (shard.databaseId) return shard.databaseId;
  if (shard.databaseIdEnv && process.env[shard.databaseIdEnv]) return process.env[shard.databaseIdEnv];
  if (shard.databaseIdEnv === 'D1_DATABASE_ID') return 'YOUR_D1_DATABASE_ID';
  throw new Error(`Missing database ID for ${shard.binding}`);
}

function uniquePhysicalBindings(manifest) {
  const byBinding = new Map();
  const byOrdinal = new Map();
  for (const shard of manifest.shards) {
    if (!['legacy', 'precreated', 'active', 'draining'].includes(shard.state)) continue;
    const id = databaseId(shard);
    const existing = byBinding.get(shard.binding);
    if (existing && existing.database_id !== id) throw new Error(`Binding drift for ${shard.binding}`);
    byBinding.set(shard.binding, {
      binding: shard.binding,
      database_name: shard.databaseName,
      database_id: id,
    });
    if (shard.ordinal > 0) {
      const previous = byOrdinal.get(shard.ordinal);
      if (previous && previous !== shard.binding) throw new Error(`Ordinal ${shard.ordinal} maps to multiple bindings`);
      byOrdinal.set(shard.ordinal, shard.binding);
    }
  }
  return [...byBinding.values()].sort((left, right) => left.binding.localeCompare(right.binding));
}

export function validateBindingBudget(entries, source = process.env) {
  const softLimit = Number(source.D1_BINDING_SOFT_LIMIT || 4_000);
  const metadataReserveBytes = Number(source.D1_BINDING_METADATA_RESERVE_BYTES || 250_000);
  if (!Number.isInteger(softLimit) || softLimit < 1 || softLimit > DOCUMENTED_D1_BINDING_LIMIT) {
    throw new Error('D1_BINDING_SOFT_LIMIT must be an integer between 1 and 5000');
  }
  if (!Number.isInteger(metadataReserveBytes) || metadataReserveBytes < 0 || metadataReserveBytes >= SCRIPT_METADATA_LIMIT_BYTES) {
    throw new Error('D1_BINDING_METADATA_RESERVE_BYTES must be between 0 and 999999');
  }
  const metadataBound = Math.floor(
    (SCRIPT_METADATA_LIMIT_BYTES - metadataReserveBytes) / RESOURCE_BINDING_ESTIMATED_BYTES,
  );
  const calculatedMaximum = Math.min(DOCUMENTED_D1_BINDING_LIMIT, metadataBound);
  if (entries.length > calculatedMaximum) {
    throw new Error(
      `D1 binding count ${entries.length} exceeds calculated single-Worker maximum ${calculatedMaximum}; split ordinal ranges into shard gateway Workers`,
    );
  }
  if (entries.length > softLimit) {
    throw new Error(
      `D1 binding count ${entries.length} exceeds operational soft limit ${softLimit}; generate shard gateway manifests before adding another shard`,
    );
  }
  return {
    count: entries.length,
    softLimit,
    calculatedMaximum,
    estimatedMetadataBytes: entries.length * RESOURCE_BINDING_ESTIMATED_BYTES + metadataReserveBytes,
  };
}

function replaceDatabases(source, entries) {
  const marker = /"d1_databases"\s*:\s*\[[\s\S]*?\n\s*\](?=\s*(?:,|\n\s*}))/;
  if (!marker.test(source)) throw new Error('Could not find d1_databases section');
  const rendered = JSON.stringify(entries, null, '\t').split('\n').map((line) => `\t${line}`).join('\n');
  return source.replace(marker, `"d1_databases": ${rendered.trimStart()}`);
}

export async function renderBindings() {
  const manifest = JSON.parse(await readFile(manifestUrl, 'utf8'));
  const entries = uniquePhysicalBindings(manifest);
  validateBindingBudget(entries);
  for (const target of targets) {
    const url = new URL(target, root);
    const source = await readFile(url, 'utf8');
    await writeFile(url, replaceDatabases(source, entries));
  }
  const routes = manifest.shards
    .filter((shard) => shard.ordinal > 0)
    .sort((left, right) => left.ordinal - right.ordinal)
    .map(({ family, cohort, epoch, ordinal, binding, state }) => ({ family, cohort, epoch, ordinal, binding, state }));
  const generated = `// Generated by .github/scripts/render-d1-bindings.mjs; do not edit.\nimport type { ShardFamily, ShardLifecycleState } from '../types/sharding';\nexport interface GeneratedD1ShardRoute { readonly family: ShardFamily; readonly cohort: number; readonly epoch: number; readonly ordinal: number; readonly binding: string; readonly state: ShardLifecycleState }\nexport const GENERATED_D1_SHARD_ROUTES: readonly GeneratedD1ShardRoute[] = ${JSON.stringify(routes, null, 2)};\n`;
  await writeFile(new URL('packages/shared/generated/d1-shard-routes.ts', root), generated);
}

if (process.argv[1] && import.meta.url === new URL(`file://${process.argv[1]}`).href) {
  renderBindings().catch((error) => {
    process.stderr.write(`${error instanceof Error ? error.message : String(error)}\n`);
    process.exitCode = 1;
  });
}
